mapper.select:
       SELECT * FROM (
	        SELECT A.*, ROWNUM AS rNum FROM (
	            SELECT 
	                p.place_id,
	                p.place_type,
	                p.name,
	                p.address,
	                p.view_count,
	                p.image_url,
	                p.created_at AS placeRegDate  FROM PLACE p, RESTAURANT r
	            WHERE p.place_id = r.restaurant_id
	              AND r.areacode = #{areacode}
	            ORDER BY p.place_id DESC
	        ) A
	        WHERE ROWNUM <= #{end}
	    ) WHERE rNum >= #{start}

SELECT COUNT(*) 
FROM RESTAURANT 
WHERE Restaurant_ID = #{restaurant_id}

