    SELECT place_id_seq.CURRVAL FROM DUAL

INSERT INTO PLACE (
    place_id, place_type, name, address, view_count, latitude, longitude, image_url, created_at
) VALUES (
    place_id_seq.NEXTVAL, 'REST', #{name}, #{address}, 0, #{latitude}, #{longitude}, #{image_url}, SYSTIMESTAMP
)

